import json, re

# Get the WiFi businesses data
wifi_result = locals()['var_functions.query_db:12']

# Load from file if needed
if isinstance(wifi_result, str) and wifi_result.endswith('.json'):
    with open(wifi_result, 'r') as f:
        wifi_businesses_raw = json.load(f)
else:
    wifi_businesses_raw = wifi_result

print('Total records: ' + str(len(wifi_businesses_raw)))

# Look at WiFi values and descriptions
wifi_count = 0
no_wifi_count = 0
sample_desc = []

for b in wifi_businesses_raw[:50]:
    if isinstance(b.get('attributes'), dict) and b['attributes'].get('WiFi'):
        wifi_val = str(b['attributes']['WiFi']).lower()
        wifi_count += 1
        if 'no' in wifi_val:
            no_wifi_count += 1
        desc = b.get('description', '')
        if desc and len(desc) > 50:
            sample_desc.append(desc[:100])

print('WiFi records examined: ' + str(wifi_count))
print('Records with no WiFi: ' + str(no_wifi_count))
print('Sample descriptions:')
for d in sample_desc[:3]:
    print('  ' + d)

# Try to extract states
wifi_businesses = []
us_states = ['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY']

state_pattern = re.compile(r'\b([A-Z]{2})\b')

for b in wifi_businesses_raw:
    if isinstance(b.get('attributes'), dict) and b['attributes'].get('WiFi'):
        wifi_val = str(b['attributes']['WiFi']).lower()
        if 'no' not in wifi_val:
            desc = b.get('description', '')
            matches = state_pattern.findall(desc)
            for state in matches:
                if state in us_states:
                    wifi_businesses.append({
                        'business_id': b['business_id'],
                        'name': b['name'],
                        'state': state,
                        'wifi': b['attributes']['WiFi']
                    })
                    break

print('WiFi businesses with US state: ' + str(len(wifi_businesses)))

if wifi_businesses:
    from collections import Counter
    state_counts = Counter([b['state'] for b in wifi_businesses])
    top_states = state_counts.most_common(10)
    print('Top states: ' + str(top_states))

    result = {
        'wifi_businesses': wifi_businesses,
        'state_counts': dict(state_counts)
    }
else:
    result = {'error': 'none found'}

print('__RESULT__:')
print(json.dumps(result))

