import json, re

wifi_data = locals()['var_functions.query_db:28']
print('Total business records: ' + str(len(wifi_data)))

wifi_businesses = []
us_states = ['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY']

for business in wifi_data:
    attrs = business.get('attributes')
    if isinstance(attrs, dict) and 'WiFi' in attrs:
        wifi_val = str(attrs['WiFi']).lower()
        # Skip businesses that explicitly say no WiFi
        if 'no' not in wifi_val:
            desc = business.get('description', '')
            # Look for state in format: "in City, ST" or "in City, ST,"
            match = re.search(r',\s*([A-Z]{2})[.,]', desc)
            if match:
                state = match.group(1)
                if state in us_states:
                    wifi_businesses.append({
                        'business_ref': business['business_id'].replace('businessid_', 'businessref_'),
                        'state': state,
                        'name': business['name'],
                        'wifi': attrs['WiFi']
                    })

print('WiFi businesses with valid state: ' + str(len(wifi_businesses)))

# Count by state
from collections import Counter
if wifi_businesses:
    state_counts = Counter([b['state'] for b in wifi_businesses])
    top_states = state_counts.most_common(5)
    print('Top 5 states: ' + str(top_states))

    if top_states:
        top_state_code = top_states[0][0]
        top_state_businesses = [b for b in wifi_businesses if b['state'] == top_state_code]
        business_refs = [b['business_ref'] for b in top_state_businesses]

        result = {
            'top_state': top_state_code,
            'count': len(top_state_businesses),
            'business_refs': business_refs,
            'total_wifi': len(wifi_businesses)
        }
    else:
        result = {'error': 'no top state'}
else:
    result = {'error': 'no businesses'}

print('__RESULT__:')
print(json.dumps(result))

